function check_killGauge_zeros_weights(address gauge) public {
    // Setup: gauge exists and has non-zero weight
    vm.assume(gaugesState[gauge].isGauge);
    vm.assume(gaugesState[gauge].isAlive);
    address pool = gaugesState[gauge].pool;
    uint256 epochTs = _epochTimestamp();
    uint256 weightBefore = weightsPerEpoch[epochTs][pool];
    vm.assume(weightBefore > 0);

    // Action: kill the gauge as governance
    vm.prank(governance);
    killGauge(gauge);

    // Postcondition: weightsPerEpoch must be zero
    uint256 weightAfter = weightsPerEpoch[epochTs][pool];
    assert(weightAfter == 0);
}
